parameters.jsCode:
const body = $input.item.json.body || $input.item.json;

const nombre = body.nombre || body.name || 'Viajero';
const email = body.email || '';
const telefono = body.telefono || body.phone || '';
const naviera = body.naviera || body.cruise_line || 'No especificada';
const destino = body.destino || body.destination || 'No especificado';
const presupuesto = body.presupuesto || body.budget || 'No especificado';
const fechaViaje = body.fecha_viaje || body.travel_date || 'Flexible';
const origen = body.utm_source || body.source || 'directo';
const campaign = body.utm_campaign || 'organico';

const leadScore = (
  (email ? 20 : 0) +
  (telefono ? 25 : 0) +
  (naviera !== 'No especificada' ? 20 : 0) +
  (presupuesto !== 'No especificado' ? 20 : 0) +
  (fechaViaje !== 'Flexible' ? 15 : 0)
);

const prioridad = leadScore >= 70 ? '🔥 ALTA' : leadScore >= 40 ? '⚡ MEDIA' : '📌 BAJA';

return [{
  json: {
    nombre, email, telefono,
    naviera, destino, presupuesto, fechaViaje,
    origen, campaign,
    lead_score: leadScore,
    prioridad,
    fecha_registro: new Date().toISOString(),
    lead_id: `GC-LEAD-${Date.now()}`
  }
}];

